edits.old:
if (abs(hpx[j] - hpx[j + 1]) < 1e-12) {
  z[j + 1] <- (x[j] + x[j + 1]) / 2          # parallel tangents (log-linear)
} else {
  z[j + 1] <- (hx[j + 1] - hx[j] - x[j + 1] * hpx[j + 1] + x[j] * hpx[j]) /
              (hpx[j] - hpx[j + 1])
}

edits.new:
denom <- hpx[j] - hpx[j + 1]
if (abs(denom) < 1e-10 * (1 + abs(hpx[j]))) {
  z[j + 1] <- (x[j] + x[j + 1]) / 2          # parallel tangents (log-linear)
} else {
  zj <- (hx[j + 1] - hx[j] - x[j + 1] * hpx[j + 1] + x[j] * hpx[j]) / denom
  # numerical guard: a concave-hull breakpoint must lie between abscissae
  if (!is.finite(zj) || zj < x[j] || zj > x[j + 1])
    zj <- (x[j] + x[j + 1]) / 2
  z[j + 1] <- zj
}
